import{_ as t,o as a,c as o,ag as r}from"./chunks/framework.DXGyWiRo.js";const g=JSON.parse('{"title":"About IT Gateway","description":"","frontmatter":{"title":"About IT Gateway","nav_order":99},"headers":[],"relativePath":"about.md","filePath":"about.md"}'),i={name:"about.md"};function s(n,e,l,h,u,c){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="about-it-gateway" tabindex="-1">About IT Gateway <a class="header-anchor" href="#about-it-gateway" aria-label="Permalink to &quot;About IT Gateway&quot;">​</a></h1><p>IT Gateway is a free, open educational resource for South African high school students studying <strong>Information Technology</strong> in Grades 10, 11 and 12.</p><h2 id="what-this-site-covers" tabindex="-1">What this site covers <a class="header-anchor" href="#what-this-site-covers" aria-label="Permalink to &quot;What this site covers&quot;">​</a></h2><p>The content is aligned to the <strong>CAPS (Curriculum and Assessment Policy Statement)</strong> for Information Technology, covering both examination papers:</p><ul><li><strong>Paper 2 (Theory)</strong> — Systems Technologies, Communication Technologies, Internet Technologies, Data &amp; Information Management, Social Implications, and Solution Development theory.</li><li><strong>Paper 1 (Practical)</strong> — Delphi programming, SQL, algorithms and number systems.</li></ul><h2 id="who-is-this-for" tabindex="-1">Who is this for? <a class="header-anchor" href="#who-is-this-for" aria-label="Permalink to &quot;Who is this for?&quot;">​</a></h2><ul><li><strong>Students</strong> who want clear explanations, worked examples and exam-style practice.</li><li><strong>Teachers</strong> looking for a well-organised supplementary resource to share with learners.</li><li><strong>Self-study learners</strong> working through the CAPS IT curriculum independently.</li></ul><h2 id="how-to-use-this-site" tabindex="-1">How to use this site <a class="header-anchor" href="#how-to-use-this-site" aria-label="Permalink to &quot;How to use this site&quot;">​</a></h2><ul><li>Use the <strong>Theory</strong> section to study for Paper 2.</li><li>Use the <strong>Practical</strong> section to prepare for Paper 1 coding questions.</li><li>Use <strong>Quick Study</strong> pages for fast revision before tests and exams.</li></ul><h2 id="disclaimer" tabindex="-1">Disclaimer <a class="header-anchor" href="#disclaimer" aria-label="Permalink to &quot;Disclaimer&quot;">​</a></h2><p>IT Gateway is an independent resource and is not affiliated with the Department of Basic Education or any examination board. While every effort is made to align content with the current CAPS curriculum, students should always refer to their official CAPS document and their teacher&#39;s guidance.</p><h2 id="contributing" tabindex="-1">Contributing <a class="header-anchor" href="#contributing" aria-label="Permalink to &quot;Contributing&quot;">​</a></h2><p>This site is open source. If you spot an error, have a suggestion, or want to contribute content, please open an issue or pull request on the GitHub repository.</p><hr><p><em>Built with <a href="https://vitepress.dev" target="_blank" rel="noreferrer">VitePress</a>. Content license: CC BY-SA 4.0.</em></p>',15)])])}const p=t(i,[["render",s]]);export{g as __pageData,p as default};
